SET NAMES utf8mb4;
USE ai_command_atlas;


-- commands
INSERT INTO `commands` (`id`, `tool_id`, `slug`, `name`, `command_type`, `category`, `risk_level`, `source`, `description`, `description_zh`, `syntax`, `value_hint`, `parameters`, `examples`, `notes`, `notes_zh`, `caveats`, `caveats_zh`, `source_url`, `source_note`, `related_command_ids`, `last_checked`, `created_at`, `updated_at`) VALUES (1,1,'model','--model','option','Model','low','official','Sets the model for the current session with an alias for the latest model (sonnet or opus) or a model’s full name. Overrides the model setting and ANTHROPIC_MODEL','指定当前会话使用的 AI 模型。','claude --model',NULL,NULL,'[{\"code\": \"claude --model claude-sonnet-4-6\", \"lang\": \"shell\", \"label\": \"Usage\"}]',NULL,NULL,NULL,NULL,'https://code.claude.com/docs/en/cli-reference','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(2,1,'dangerously-skip-permissions','--dangerously-skip-permissions','flag','Permission','high','official','Skip permission prompts. Equivalent to --permission-mode bypassPermissions. See permission modes for what this does and does not skip','跳过所有权限确认提示——在生产环境中使用极其危险。允许代理在无需用户确认的情况下执行任何操作。','claude --dangerously-skip-permissions',NULL,NULL,'[{\"code\": \"claude --dangerously-skip-permissions\", \"lang\": \"shell\", \"label\": \"Usage\"}]','[\"Only use in trusted sandboxed environments (Docker, CI)\", \"Equivalent to --permission-mode bypassPermissions but with no safety net\", \"Cannot be combined with --permission-mode\"]','[\"仅在受信任的沙盒环境（Docker、CI）中使用\", \"等同于 --permission-mode bypassPermissions，但没有任何安全保护\", \"不能与 --permission-mode 同时使用\"]','[\"The agent can execute arbitrary shell commands, delete files, and modify system state without confirmation\", \"If used outside a sandbox, there is no rollback — damage is immediate and permanent\"]','[\"代理可以在无需确认的情况下执行任意 shell 命令、删除文件、修改系统状态\", \"如果在沙盒外使用，没有回滚机制——损害是即时且永久的\"]','https://code.claude.com/docs/en/cli-reference','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(3,1,'permission-mode','--permission-mode','option','Permission','medium','official','Begin in a specified permission mode. Accepts default, acceptEdits, plan, auto, dontAsk, or bypassPermissions. Overrides defaultMode from settings files','控制权限级别：default（所有操作均需确认）、acceptEdits（自动接受文件编辑）、bypassPermissions（完全跳过权限检查）。','claude --permission-mode','<default|acceptEdits|bypassPermissions>',NULL,'[{\"code\": \"claude --permission-mode plan\", \"lang\": \"shell\", \"label\": \"Usage\"}]','[\"Three modes: default (ask for everything), acceptEdits (auto-accept file writes), bypassPermissions (skip all prompts)\", \"acceptEdits is the most common middle-ground for active development\"]','[\"三种模式：default（所有操作均需确认）、acceptEdits（自动接受文件写入）、bypassPermissions（跳过所有提示）\", \"acceptEdits 是日常开发中最常用的折中选项\"]','[\"bypassPermissions is functionally identical to --dangerously-skip-permissions\"]','[\"bypassPermissions 在功能上等同于 --dangerously-skip-permissions\"]','https://code.claude.com/docs/en/cli-reference','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(4,1,'resume','resume','subcommand','Session','low','official','Resume session by ID or name','通过会话 ID 恢复之前的对话。','claude -r \"<session>\" \"query\"','[session-id]',NULL,'[{\"code\": \"claude -r \\\"auth-refactor\\\" \\\"Finish this PR\\\"\", \"lang\": \"shell\", \"label\": \"Usage\"}]',NULL,NULL,NULL,NULL,'https://code.claude.com/docs/en/cli-reference','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(5,1,'mcp','mcp','subcommand','MCP','medium','official','Configure Model Context Protocol (MCP) servers','管理 MCP（Model Context Protocol）服务器连接：添加、移除、列出、运行服务器。','claude mcp',NULL,NULL,'[{\"code\": \"See the Claude Code MCP documentation.\", \"lang\": \"shell\", \"label\": \"Usage\"}]',NULL,NULL,NULL,NULL,'https://code.claude.com/docs/en/cli-reference','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(6,1,'mcp-add','mcp add','subcommand','MCP','medium','official','Register a new MCP tool server. Supports stdio, sse, and http transports.','注册新的 MCP 工具服务器。支持 stdio、sse 和 http 传输方式。','claude mcp add --transport <transport> <name>',NULL,NULL,'[{\"code\": \"claude mcp add --transport stdio my-server -- npx -y @my-org/mcp-server\", \"lang\": \"shell\", \"label\": \"Add a stdio-based MCP server\"}, {\"code\": \"claude mcp add --transport stdio --scope project my-server -- node server.js\", \"lang\": \"shell\", \"label\": \"Add to project scope instead of user scope\"}]','[\"Supports three transports: stdio, sse, http\", \"Server config is stored in ~/.claude/settings.json\"]','[\"支持三种传输方式：stdio、sse、http\", \"服务器配置存储在 ~/.claude/settings.json 中\"]',NULL,NULL,'https://docs.anthropic.com/en/docs/claude-code/mcp','Verified against official Claude Code MCP documentation.',NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(7,1,'config','config','subcommand','Config','low','official','Open the Settings interface to adjust theme, model, output style, and other preferences. Alias: /settings','查看或修改存储在 ~/.claude/settings.json 中的持久化设置。','/config',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://code.claude.com/docs/en/commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(8,1,'compact','/compact','slash','Session','low','official','Free up context by summarizing the conversation so far. Optionally pass focus instructions for the summary. See how compaction handles rules, skills, and memory files','压缩当前对话上下文，释放 context window 令牌空间，以支持更长的编码会话。','/compact [instructions]',NULL,NULL,'[{\"code\": \"> /compact Keep the bug in auth.ts we just fixed and the test structure. Forget the failed attempts.\", \"lang\": \"shell\", \"label\": \"After a long debugging session\"}, {\"code\": \"> /compact Summarise the database migration work. I am now working on the API layer.\", \"lang\": \"shell\", \"label\": \"Before switching to a new subtask\"}]','[\"Compaction uses the model itself to write the summary — quality depends on how well you phrase the optional instructions. Be specific about tasks in progress.\", \"The original conversation history is discarded after compaction — there is no undo. If you need the full context, use resume to start a new session instead.\", \"Works best after a clearly defined phase has completed (e.g. after a bug fix, before switching features).\"]','[\"压缩使用模型自身来生成摘要——摘要质量取决于你对可选指令的措辞。请明确描述正在进行的任务。\", \"压缩后原始对话历史将被丢弃，且无法撤销。如果需要完整上下文，请改用 resume 开启新会话。\", \"建议在某个明确阶段完成后使用（例如修完一个 bug 后、切换功能前）。\"]','[\"The summary is non-deterministic — two identical invocations may produce slightly different summaries depending on the model sampling.\", \"Tool call outputs (large file reads, long command output) may be summarised aggressively. If a specific shell output is critical, quote it explicitly in your instructions.\"]','[\"摘要具有非确定性——两次相同的调用可能会因模型采样不同而产生略有差异的摘要。\", \"工具调用的输出（大文件读取、长命令输出）可能会被大幅精简。如果某个特定输出很关键，请在指令中明确引用。\"]','https://code.claude.com/docs/en/commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(9,1,'clear','/clear','slash','Session','low','official','Start a new conversation with empty context. The previous conversation stays available in /resume. Pass a name to label the previous conversation in the /resume picker. To free up context while continuing the same conversation, use /compact instead. Aliases: /reset, /new','清除当前对话历史并重新开始。别名：/reset。','/clear [name]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://code.claude.com/docs/en/commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(10,1,'help','/help','slash','Session','low','official','Show help and available commands','显示所有可用的 slash 命令及其说明。','/help',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://code.claude.com/docs/en/commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(11,1,'memory','/memory','slash','Config','low','official','Edit CLAUDE.md memory files, enable or disable auto-memory, and view auto-memory entries','读取或写入持久化的 CLAUDE.md 记忆文件。','/memory',NULL,NULL,'[{\"code\": \"> /memory\", \"lang\": \"shell\", \"label\": \"Open memory for reading and editing\"}, {\"code\": \"> /memory Always use single quotes in TypeScript files in this project.\", \"lang\": \"shell\", \"label\": \"Ask Claude to remember a preference\"}]','[\"Writes to CLAUDE.md in the project root or ~/.claude/CLAUDE.md globally\", \"Memory persists across sessions\"]','[\"写入项目根目录的 CLAUDE.md 或全局的 ~/.claude/CLAUDE.md\", \"记忆内容在会话之间持久保存\"]',NULL,NULL,'https://code.claude.com/docs/en/commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:28'),(12,1,'claude-md','CLAUDE.md','config','Config','low','official','Project or global instructions file injected into every session. Checked in project root or home directory.','项目级或全局指令文件，在每次会话中自动注入。可放置在项目根目录或用户主目录。','CLAUDE.md',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://docs.anthropic.com/en/docs/claude-code',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(13,2,'compact','/compact','slash','Session','low','official','Summarize the visible conversation to free tokens. Use after long runs so Codex retains key points without blowing the context window.','压缩当前对话上下文，释放 context window 令牌空间。','/compact',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://developers.openai.com/codex/cli/slash-commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:48'),(14,2,'help','/help','slash','Session','low','official','Display all available slash commands and their descriptions.','显示所有可用的 slash 命令及其说明。','/help',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(15,2,'clear','/clear','slash','Session','low','official','Clear the terminal and start a fresh chat. Reset the visible UI and conversation together when you want a fresh start.','清除当前对话历史并重新开始。','/clear',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://developers.openai.com/codex/cli/slash-commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:48'),(16,2,'history','/history','slash','Session','low','official','Show a paginated log of the current conversation history.','显示当前对话历史的分页日志。','/history',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(17,2,'model','--model','option','Model','low','official','Choose the active model (and reasoning effort, when available). Switch between general-purpose models (gpt-4.1-mini) and deeper reasoning models before running a task.','指定要使用的 OpenAI 模型（例如 o4-mini、gpt-4o）。','/model','-m <model-id>',NULL,NULL,NULL,NULL,NULL,NULL,'https://developers.openai.com/codex/cli/slash-commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:48'),(18,2,'provider','--provider','option','Model','low','official','Select the AI provider backend (openai, azure, ollama, anthropic).','选择 AI 提供商后端（openai、azure、ollama、anthropic）。','--provider <provider>','<provider>',NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(19,2,'temperature','--temperature','option','Model','low','github','Control model sampling randomness. Float 0.0–2.0.','控制模型采样的随机性。浮点数，范围 0.0–2.0。','--temperature <float>','<0.0-2.0>',NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(20,2,'approval-mode','--approval-mode','option','Permission','medium','official','Choose the approval mode that matches your comfort level before Codex edits or runs commands.','控制代理在执行操作前如何请求用户批准。','codex --approval-mode <mode>','<suggest|auto-edit|full-auto>',NULL,'[{\"code\": \"codex --approval-mode suggest \\\"Explain this function\\\"\", \"lang\": \"shell\", \"label\": \"Suggest-only mode (default, safest)\"}, {\"code\": \"codex --approval-mode auto-edit \\\"Add input validation to handler.ts\\\"\", \"lang\": \"shell\", \"label\": \"Auto-edit — writes files, asks before shell commands\"}, {\"code\": \"codex --approval-mode full-auto \\\"Fix the failing tests\\\"\", \"lang\": \"shell\", \"label\": \"Full-auto — no prompts at all\"}]','[\"Three modes: suggest (read-only), auto-edit (write files, ask for commands), full-auto (no prompts)\", \"Default is suggest\"]','[\"三种模式：suggest（只读建议）、auto-edit（自动写入文件，执行命令需确认）、full-auto（无需任何提示）\", \"默认模式为 suggest\"]','[\"full-auto mode allows arbitrary command execution without confirmation\"]','[\"full-auto 模式允许无需确认即可执行任意命令\"]','https://developers.openai.com/codex/cli','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:48'),(21,2,'sandbox','--sandbox','flag','Permission','low','github','Run the agent inside an isolated sandbox environment (macOS Sandbox or Docker).','在隔离的沙盒环境中运行代理（macOS Sandbox 或 Docker）。','--sandbox[=<policy>]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(22,2,'full-auto','--full-auto','flag','Permission','high','official','Enable fully autonomous execution — agent acts without any approval prompts.','启用完全自主执行模式——代理在无需任何批准提示的情况下运行。','--full-auto',NULL,NULL,'[{\"code\": \"codex --full-auto --sandbox \\\"Run tests and fix any failures\\\"\", \"lang\": \"shell\", \"label\": \"Full-auto with sandbox protection\"}, {\"code\": \"codex --full-auto \\\"Refactor the auth module\\\"\", \"lang\": \"shell\", \"label\": \"Full-auto without sandbox (dangerous)\"}]','[\"Shorthand for --approval-mode full-auto\", \"Best used with --sandbox for safety\"]','[\"等同于 --approval-mode full-auto 的简写\", \"建议搭配 --sandbox 使用以确保安全\"]','[\"Agent can execute any shell command without confirmation\", \"Network access is unrestricted unless sandboxed\"]','[\"代理可以在无需确认的情况下执行任意 shell 命令\", \"除非启用沙盒，否则网络访问不受限制\"]','https://github.com/openai/codex','Verified against Codex CLI README.',NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(23,2,'dangerously-auto-approve-everything','--dangerously-auto-approve-everything','flag','Permission','high','official','Auto-approve all actions without confirmation — use only in trusted, isolated environments.','自动批准所有操作且不进行确认——仅在受信任的隔离环境中使用。','--dangerously-auto-approve-everything',NULL,NULL,'[{\"code\": \"docker run --rm -v $(pwd):/work -w /work codex-cli --dangerously-auto-approve-everything \\\"Migrate database schema\\\"\", \"lang\": \"shell\", \"label\": \"In a disposable Docker container\"}]','[\"Same as --full-auto but with explicit danger naming\", \"Intended for fully isolated environments only\"]','[\"与 --full-auto 相同，但命名上明确标注了危险性\", \"仅适用于完全隔离的环境\"]','[\"No safety prompts of any kind — all actions are auto-approved\", \"Should only be used in disposable containers\"]','[\"没有任何安全提示——所有操作均自动批准\", \"应仅在一次性容器中使用\"]','https://github.com/openai/codex','Verified against Codex CLI README.',NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(24,2,'quiet','--quiet','flag','Config','low','official','Suppress verbose output, only show essential messages and results.','抑制详细输出，仅显示关键信息和结果。','--quiet','-q',NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(25,2,'json','--json','flag','Config','low','official','Output structured JSON instead of human-readable text.','输出结构化 JSON 格式，而非人类可读的文本。','--json',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(26,2,'config-path','--config','option','Config','low','official','Specify a custom path to the Codex configuration file.','指定 Codex 配置文件的自定义路径。','--config <path>','<path>',NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(27,2,'context-window-size','--context-window-size','option','Config','low','github','Override the default maximum context window token limit.','覆盖默认的 context window 最大令牌数限制。','--context-window-size <tokens>','<tokens>',NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(28,2,'config','config','subcommand','Config','low','official','View or interactively edit persistent Codex configuration values.','查看或交互式编辑持久化的 Codex 配置值。','codex config [get|set] [key] [value]',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(29,2,'resume','resume','subcommand','Session','low','official','Resume a saved conversation from your session list. Continue work from a previous CLI session without starting over.','通过会话 ID 恢复之前的 Codex 会话，或从历史记录中交互式选择。','/resume','[session-id]',NULL,NULL,NULL,NULL,NULL,NULL,'https://developers.openai.com/codex/cli/slash-commands','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:37:48'),(30,2,'agents-md','AGENTS.md','config','Config','low','official','Agent instructions file loaded at project level, injected into every session.','项目级代理指令文件，在每次会话中自动注入。','AGENTS.md',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://github.com/openai/codex',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(31,3,'model','--model','option','Model','low','official','Model to use. See Model Selection for available values.','选择 Gemini 模型变体（例如 gemini-2.5-pro）。','gemini --model <string>','<model-id>',NULL,'[{\"code\": \"gemini --model gemini-2.5-flash\", \"lang\": \"shell\", \"label\": \"Select a specific Gemini model\"}, {\"code\": \"gemini --model gemini-2.5-pro\", \"lang\": \"shell\", \"label\": \"Use the default model explicitly\"}]','[\"Alias: -m\", \"Default: auto\"]','[\"默认模型为 gemini-2.5-pro\", \"仅支持 Google 模型\"]',NULL,NULL,'https://www.geminicli.com/docs/cli/cli-reference/','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:34:09'),(32,3,'compress','/compress','slash','Session','low','official','Compress conversation history to free up context window.','压缩对话历史以释放 context window 空间。','/compress',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://ai.google.dev/gemini-api/docs/gemini-cli',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(33,3,'clear','/clear','slash','Session','low','official','Clear the current conversation history.','清除当前对话历史。','/clear',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://ai.google.dev/gemini-api/docs/gemini-cli',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(34,3,'help','/help','slash','Session','low','official','Show help for all commands','显示可用命令及使用说明。','/help',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://www.geminicli.com/docs/cli/cli-reference/','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:25:43','2026-06-08 11:34:09'),(35,3,'config','config','subcommand','Config','low','official','View or edit Gemini CLI configuration stored in ~/.gemini/config.yaml.','查看或编辑存储在 ~/.gemini/config.yaml 中的 Gemini CLI 配置。','gemini config',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://ai.google.dev/gemini-api/docs/gemini-cli',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(36,3,'gemini-md','GEMINI.md','config','Config','low','official','Custom instructions file loaded from project root, injected into every session.','从项目根目录加载的自定义指令文件，在每次会话中自动注入。','GEMINI.md',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'https://ai.google.dev/gemini-api/docs/gemini-cli',NULL,NULL,'2026-05-28','2026-06-08 11:25:43','2026-06-08 11:25:43'),(37,4,'model','--model','opti