.html#--alias-aliasmodel','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(65,4,'reasoning-effort','--reasoning-effort','option','Model','low','official','Set the reasoning_effort API parameter (default: not set)','设置 reasoning_effort API 参数（默认：未设置）','aider --reasoning-effort VALUE','VALUE',NULL,NULL,'[\"Environment variable: AIDER_REASONING_EFFORT\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--reasoning-effort-value','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(66,4,'thinking-tokens','--thinking-tokens','option','Model','low','official','Set the thinking token budget for models that support it. Use 0 to disable. (default: not set)','为支持该功能的 model 设置思考 token 预算。设为 0 可禁用。（默认：未设置）','aider --thinking-tokens VALUE','VALUE',NULL,NULL,'[\"Environment variable: AIDER_THINKING_TOKENS\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--thinking-tokens-value','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(67,4,'verify-ssl','--verify-ssl','flag','Model','low','official','Verify the SSL cert when connecting to models (default: True) Default: True  Aliases:','连接 model 时验证 SSL 证书（默认值：True）默认值：True 别名：','aider --verify-ssl',NULL,NULL,NULL,'[\"Environment variable: AIDER_VERIFY_SSL\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--verify-ssl','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(68,4,'timeout','--timeout','option','Model','low','official','Timeout in seconds for API calls (default: None)','API 调用的 timeout 时间，单位为秒（默认：None）','aider --timeout VALUE','VALUE',NULL,NULL,'[\"Environment variable: AIDER_TIMEOUT\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--timeout-value','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(69,4,'edit-format','