e: AIDER_ADD_GITIGNORE_FILES\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--add-gitignore-files','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(105,4,'aiderignore','--aiderignore','option','Config','low','official','Specify the aider ignore file (default: .aiderignore in git root) Default: .aiderignore','指定 aider 忽略文件（默认：git 根目录下的 .aiderignore）默认值：.aiderignore','aider --aiderignore AIDERIGNORE','AIDERIGNORE',NULL,NULL,'[\"Environment variable: AIDER_AIDERIGNORE\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--aiderignore-aiderignore','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(106,4,'subtree-only','--subtree-only','flag','Config','low','official','Only consider files in the current subtree of the git repository Default: False','仅考虑当前 git repository 子树中的文件 默认值：False','aider --subtree-only',NULL,NULL,NULL,'[\"Environment variable: AIDER_SUBTREE_ONLY\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--subtree-only','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(107,4,'auto-commits','--auto-commits','flag','Config','medium','official','Enable/disable auto commit of LLM changes (default: True) Default: True  Aliases:','启用/禁用 LLM 更改的自动 commit（默认值：True）。默认值：True  别名：','aider --auto-commits',NULL,NULL,NULL,'[\"Environment variable: AIDER_AUTO_COMMITS\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--auto-commits','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(108,4,'dirty-commits','--dirty-commits','flag','Config','low','official','Enable/disable commits when repo is found dirty (default: True) Default: True  Aliases:','启用/禁用在 repository 存在未提交更改时自动执行 commit 的功能（默认：True）默认值：True  别名：','aider --dirty-commits',NULL,NULL,NULL,'[\"Environment variable: AIDER_DIRTY_COMMITS\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--dirty-commits','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(109,4,'attribute-author','--attribute-author','flag','Config','low','official','Attribute aider code changes in the git author name (default: True). If explicitly set to True, overrides –attribute-co-authored-by precedence.  Aliases:','在 git author 名称中标注 aider 代码更改（默认值：True）。若显式设置为 True，则覆盖 –attribute-co-authored-by 的优先级。别名：','aider --attribute-author',NULL,NULL,NULL,'[\"Environment variable: AIDER_ATTRIBUTE_AUTHOR\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--attribute-author','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(110,4,'attribute-committer','--attribute-committer','flag','Config','low','official','Attribute aider commits in the git committer name (default: True). If explicitly set to True, overrides –attribute-co-authored-by precedence for aider edits.  Aliases:','在 git committer 名称中标注 aider 的 commit（默认值：True）。若显式设置为 True，则覆盖 –attribute-co-authored-by 对 aider 编辑的优先级。别名：','aider --attribute-committer',NULL,NULL,NULL,'[\"Environment variable: AIDER_ATTRIBUTE_COMMITTER\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--attribute-committer','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(111,4,'attribute-commit-message-author','--attribute-commit-message-author','flag','Config','low','official','Prefix commit messages with ‘aider: ‘ if aider authored the changes (default: False) Default: False  Aliases:','若 aider 是更改的作者，则在 commit 消息前添加 \'aider: \' 前缀（默认值：False）。默认值：False  别名：','aider --attribute-commit-message-author',NULL,NULL,NULL,'[\"Environment variable: AIDER_ATTRIBUTE_COMMIT_MESSAGE_AUTHOR\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--attribute-commit-message-author','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(112,4,'attribute-commit-message-committer','--attribute-commit-message-committer','flag','Config','low','official','Prefix all commit messages with ‘aider: ‘ (default: False) Default: False  Aliases:','为所有 commit 消息添加 \'aider: \' 前缀（默认值：False）。默认值：False  别名：','aider --attribute-commit-message-committer',NULL,NULL,NULL,'[\"Environment variable: AIDER_ATTRIBUTE_COMMIT_MESSAGE_COMMITTER\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--attribute-commit-message-committer','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(113,4,'attribute-co-authored-by','--attribute-co-authored-by','flag','Config','low','official','Attribute aider edits using the Co-authored-by trailer in the commit message (default: True). If True, this takes precedence over default –attribute-author and –attribute-committer behavior unless they are explicitly set to True. Default: True  Aliases:','通过在 commit 消息中添加 Co-authored-by trailer 来标注 aider 编辑（默认值：True）。若为 True，除非 –attribute-author 和 –attribute-committer 被显式设置为 True，否则此选项优先于二者的默认行为。默认值：True  别名：','aider --attribute-co-authored-by',NULL,NULL,NULL,'[\"Environment variable: AIDER_ATTRIBUTE_CO_AUTHORED_BY\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--attribute-co-authored-by','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:42'),(114,4,'git-commit-verify','--git-commit-verify','flag','Config','low','official','Enable/disable git pre-commit hooks with –no-verify (default: False) Default: False  Aliases:','通过 --no-verify 启用/禁用 git pre-commit hooks（默认：False）默认值：False  别名：','aider --git-commit-verify',NULL,NULL,NULL,'[\"Environment variable: AIDER_GIT_COMMIT_VERIFY\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--git-commit-verify','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:07','2026-06-08 11:45:43'),(115,4,'commit','--commit','fl