uage COMMIT_LANGUAGE','COMMIT_LANGUAGE',NULL,NULL,'[\"Environment variable: AIDER_COMMIT_LANGUAGE\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--commit-language-commit_language','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:08','2026-06-08 11:45:43'),(155,4,'yes-always','--yes-always','flag','Config','medium','official','Always say yes to every confirmation','对每个确认始终选择同意','aider --yes-always',NULL,NULL,NULL,'[\"Environment variable: AIDER_YES_ALWAYS\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--yes-always','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:08','2026-06-08 11:45:43'),(156,4,'verbose','--verbose','flag','Config','low','official','Enable verbose output Default: False  Aliases:','启用详细输出 默认值：False 别名：','aider --verbose',NULL,NULL,NULL,'[\"Environment variable: AIDER_VERBOSE\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--verbose','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:08','2026-06-08 11:45:43'),(157,4,'load','--load','option','Config','low','official','Load and execute /commands from a file on launch','启动时从文件中加载并执行 /commands','aider --load LOAD_FILE','LOAD_FILE',NULL,NULL,'[\"Environment variable: AIDER_LOAD\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--load-load_file','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:08','2026-06-08 11:45:43'),(158,4,'encoding','--encoding','option','Config','low','official','Specify the encoding for input and output (default: utf-8) Default: utf-8','指定输入和输出的编码格式（默认：utf-8）默认值：utf-8','aider --encoding VALUE','VALUE',NULL,NULL,'[\"Environment variable: AIDER_ENCODING\"]',NULL,NULL,NULL,'https://aider.chat/docs/config/options.html#--encoding-value','Scraped from official documentation.',NULL,'2026-06-08','2026-06-08 11:34:08','2026-06-08 11:45:43'),(159,4,'line-endings','--line-endings','option','Config','low','official','Line endings 