INSERT INTO `compare_capabilities` (`id`, `capability`, `capability_zh`, `capability_desc`, `capability_desc_zh`, `category`, `sort_order`) VALUES (1,'Specify model','指定模型','Choose which model variant to use per session','选择每个会话使用的模型变体','model',1),(2,'Select provider','选择提供商','Switch between API providers (OpenAI, Anthropic, local)','切换 API 提供商（OpenAI、Anthropic、本地）','model',2),(3,'Set temperature','设置温度','Control model sampling randomness','控制模型采样的随机性','model',3),(4,'Compact context','压缩上下文','Summarise history to free context window tokens','压缩对话历史以释放 context window 令牌','session',1),(5,'Resume session','恢复会话','Continue a previous conversation by ID','通过会话 ID 继续之前的对话','session',2),(6,'Clear history','清除历史','Wipe conversation without summary','清除对话而不生成摘要','session',3),(7,'Skip permissions','跳过权限','Execute without approval prompts','无需批准提示即可执行','permission',1),(8,'Sandbox mode','沙盒模式','Isolate execution from host filesystem','将执行与主机文件系统隔离','permission',2),(9,'Approval mode','批准模式','Granular control over what auto-executes','细粒度控制自动执行的内容','permission',3),(10,'MCP support','MCP 支持','Model Context Protocol tool server integration','Model Context Protocol 工具服务器集成','mcp',1),(11,'Add MCP server','添加 MCP 服务器','Register a new tool server','注册新的工具服务器','mcp',2),(12,'View / edit config','查看/编辑配置','Inspect and modify persistent settings','查看和修改持久化设置','config',1),(13,'Custom instructions file','自定义指令文件','Project or global instructions injected into every session','注入每个会话的项目级或全局指令','config',2) ON DUPLICATE KEY UPDATE `capability_zh`=VALUES(`capability_zh`), `capability_desc_zh`=VALUES(`capability_desc_zh`);

